INSERT INTO public.store_settings ("id", "announcement_text", "hero_eyebrow", "hero_title", "hero_description", "contact_intro", "contact_phone", "contact_email", "contact_hours", "footer_blurb", "order_chat_number", "updated_at") VALUES (1, 'Mode femme & accessoires · Vente partout dans le Monde· Importation directe Chine', 'Mode Femme & Accessoires', 'Vetements, accessoires et chaussures tendance au Senegal.', 'HOTGYAAL met en avant la mode feminine: robes, tops, ensembles, sacs, bijoux et chaussures. Les produits sont selectionnes en Chine puis proposes au marche senegalais.', 'HOTGYAAL vend au Senegal et source ses collections en Chine via une activite d''import-export.', '+221 784453461', 'hotgyaal12@gmail.com', 'lundi à Dimanche, 24/7', 'Specialiste mode femme, accessoires et chaussures. Vente partout dans le monde l avec importation directe depuis la Chine.', '+221 763036760', '2026-02-27T08:04:26.364285+00:00');
